sql:
SELECT restaurant_id, name
FROM restaurants
WHERE rating > (SELECT AVG(rating) FROM restaurants);

SELECT * 
FROM restaurants 
ORDER BY rating DESC;

SELECT name, location, rating, link
FROM restaurants
WHERE location = 'London' AND rating > 4.5;

SELECT first_name, last_name
FROM users
WHERE user_id IN (
    SELECT user_id
    FROM ratings
    WHERE rating = (
        SELECT MAX(rating)
        FROM ratings
    )
);

external_knowledge:
- "eateries" is a vague term used to refer to restaurants;
- "London area" refers to the region of London;
- "review counts" are the number of distinct reviews each restaurant has received.

- "culinary havens" refers to restaurants;
- "nestled in their respective cities" refers to the location of the restaurant;
- "categorized by their financial appetites" refers to the price range of the restaurant;
- "a whisper of praise" metaphorically refers to their average rating;
- "celestial threshold of 4.5 stars" refers to an average rating greater than 4.5.

- "shining stars in the culinary universe" refers to highly-rated restaurants;
- "culinary craftsmanship has earned them a rating above the cloud ceiling" means the restaurants have a rating greater than 4.0;
- "stellar names, celestial addresses, radiant ratings, and cosmic links" refers to the restaurant's name, location, rating, and web link;
- "ranked from the brightest to the most luminous" means sorted by rating in descending order.

sql:
SELECT location, COUNT(DISTINCT restaurant_id) AS total_restaurants
FROM restaurants
GROUP BY location;
